+fn normalize_source_commit(value: &str) -> Option<String> {
+    let trimmed = value.trim();
+    if trimmed.is_empty() {
+        return None;
+    }
+
+    if trimmed.len() >= 40 && trimmed.bytes().all(|byte| byte.is_ascii_hexdigit()) {
+        return Some(trimmed[..7].to_string());
+    }
+
+    Some(trimmed.to_string())
+}
